function gridWays(center) {
  const ways = [];
  const spacing = 0.0018;
  let id = 1000;
  for (let row = -3; row <= 3; row += 1) {
    ways.push({
      type: 'way', id: id++,
      tags: { highway: row === 0 ? 'primary' : 'residential', name: row === 0 ? '中央道路' : `東西道路${row}` },
      geometry: Array.from({ length: 7 }, (_, index) => ({
        lat: center.lat + row * spacing,
        lon: center.lon + (index - 3) * spacing
      }))
    });
  }
  for (let column = -3; column <= 3; column += 1) {
    ways.push({
      type: 'way', id: id++,
      tags: { highway: column === 0 ? 'secondary' : 'residential', name: column === 0 ? '中央縦断路' : `南北道路${column}` },
      geometry: Array.from({ length: 7 }, (_, index) => ({
        lat: center.lat + (index - 3) * spacing,
        lon: center.lon + column * spacing
      }))
    });
  }
  return ways;
}

export function createDevelopmentDependencies() {
  const location = { lat: 35.7869, lon: 139.4693, accuracy: 8, timestamp: Date.now() };
  return {
    geolocation: {
      async getCurrentPosition() { return location; },
      watchPosition(onPosition) { onPosition(location); return () => {}; }
    },
    fetchImpl: async () => ({
      ok: true,
      status: 200,
      async json() { return { elements: gridWays(location) }; }
    })
  };
}

export class GameLoop {
  constructor({ store, combatSystem, civilizationSystem = null, renderer, saveRepository, onUiUpdate, onError }) {
    this.store = store;
    this.combatSystem = combatSystem;
    this.civilizationSystem = civilizationSystem;
    this.renderer = renderer;
    this.saveRepository = saveRepository;
    this.onUiUpdate = onUiUpdate;
    this.onError = onError;
    this.running = false;
    this.frameId = null;
    this.lastTime = 0;
    this.uiClock = 0;
    this.saveClock = 0;
  }

  start() {
    if (this.running) return;
    this.running = true;
    this.lastTime = performance.now();
    this.frameId = requestAnimationFrame(time => this.frame(time));
  }

  frame(time) {
    if (!this.running) return;
    const rawDelta = Math.max(0, (time - this.lastTime) / 1000);
    const deltaSeconds = Math.min(0.25, rawDelta);
    this.lastTime = time;
    this.store.mutate(state => {
      state.runtime.worldTimeMs = (state.runtime.worldTimeMs ?? Date.now()) + deltaSeconds * 1000;
      this.combatSystem.update(state, deltaSeconds);
      this.civilizationSystem?.update(state, deltaSeconds);
      state.runtime.performance.frames += 1;
      state.runtime.performance.lastFrameMs = rawDelta * 1000;
      if (rawDelta > 0.05) state.runtime.performance.slowFrames += 1;
    }, 'game:tick');
    this.renderer.render();
    this.uiClock += deltaSeconds;
    this.saveClock += deltaSeconds;
    if (this.uiClock >= 0.25) {
      this.uiClock = 0;
      this.onUiUpdate?.();
    }
    if (this.saveClock >= 5) {
      this.saveClock = 0;
      try { const savedAt = this.saveRepository.save(this.store.getState()); this.store.mutate(state => { state.runtime.lastSavedAt = savedAt; }, 'save:timestamp'); } catch (error) { this.onError?.(error); }
    }
    this.frameId = requestAnimationFrame(next => this.frame(next));
  }

  stop({ save = true } = {}) {
    if (!this.running) return;
    this.running = false;
    if (this.frameId != null) cancelAnimationFrame(this.frameId);
    this.frameId = null;
    if (save) {
      try { const savedAt = this.saveRepository.save(this.store.getState()); this.store.mutate(state => { state.runtime.lastSavedAt = savedAt; }, 'save:timestamp'); } catch (error) { this.onError?.(error); }
    }
  }
}

import { LifecycleState } from '../core/constants.js';

export class LifecycleController {
  constructor(store) {
    this.store = store;
  }

  boot() { this.store.transition(LifecycleState.LOAD_SAVE); }
  requireLocation() { this.store.transition(LifecycleState.LOCATION_REQUIRED); }
  startRoadLoading() { this.store.transition(LifecycleState.ROAD_LOADING); }
  startBaseSelection() { this.store.transition(LifecycleState.BASE_SELECTION); }
  startInitialization() { this.store.transition(LifecycleState.INITIALIZING); }
  startPlaying() { this.store.transition(LifecycleState.PLAYING); }
  pause() { this.store.transition(LifecycleState.PAUSED); }
  resume() { this.store.transition(LifecycleState.PLAYING); }
  destroy() { this.store.transition(LifecycleState.DESTROYED); }
}

export async function registerPwa() {
  const developmentFixture = new URLSearchParams(location.search).get('devFixture') === '1';
  const localHost = ['localhost', '127.0.0.1', '::1'].includes(location.hostname);
  if (developmentFixture || localHost || location.protocol !== 'https:' || !('serviceWorker' in navigator)) return null;
  try {
    return await navigator.serviceWorker.register('./sw.js', { scope: './' });
  } catch (error) {
    console.warn('Service worker registration failed', error);
    return null;
  }
}

import { stableId } from '../core/utilities.js';
import { attachGraphIndexes } from '../roads/road-graph.js';
import { xyToLatLon } from '../location/location-privacy.js';

function copyEdgeMetadata(edge) {
  return {
    barrier: null,
    roadWidth: edge.roadWidth,
    lanes: edge.lanes,
    highway: edge.highway,
    name: edge.name,
    oneway: edge.oneway,
    mergedSegmentIds: [...(edge.mergedSegmentIds ?? [])]
  };
}

export function insertBaseNodeOnEdge(graph, selection) {
  const sourceEdge = graph.edgeById.get(selection.edgeId);
  if (!sourceEdge) throw new Error('選択した道路が見つかりません。');
  const endpointThreshold = 0.04;
  if (selection.t <= endpointThreshold) {
    return { graph, nodeId: sourceEdge.a };
  }
  if (selection.t >= 1 - endpointThreshold) {
    return { graph, nodeId: sourceEdge.b };
  }

  const nextGraph = {
    ...graph,
    nodes: graph.nodes.map(node => ({ ...node })),
    edges: graph.edges.filter(edge => edge.id !== sourceEdge.id).map(edge => ({
      ...edge,
      points: edge.points?.map(point => ({ ...point })) ?? []
    }))
  };
  const location = xyToLatLon(selection.point.x, selection.point.y, graph.center);
  const nodeId = stableId('home_node', sourceEdge.id, selection.t.toFixed(6));
  nextGraph.nodes.push({
    id: nodeId,
    x: selection.point.x,
    y: selection.point.y,
    lat: location.lat,
    lon: location.lon,
    kind: 'home-base'
  });

  const a = graph.nodeById.get(sourceEdge.a);
  const b = graph.nodeById.get(sourceEdge.b);
  const firstLength = sourceEdge.length * selection.t;
  const secondLength = sourceEdge.length - firstLength;
  nextGraph.edges.push({
    id: stableId('edge', sourceEdge.id, 'a', nodeId),
    a: sourceEdge.a,
    b: nodeId,
    length: firstLength,
    points: [{ x: a.x, y: a.y }, { ...selection.point }],
    ...copyEdgeMetadata(sourceEdge)
  });
  nextGraph.edges.push({
    id: stableId('edge', sourceEdge.id, nodeId, 'b'),
    a: nodeId,
    b: sourceEdge.b,
    length: secondLength,
    points: [{ ...selection.point }, { x: b.x, y: b.y }],
    ...copyEdgeMetadata(sourceEdge)
  });

  return { graph: attachGraphIndexes(nextGraph), nodeId };
}

import { ROAD_CONFIG } from '../core/constants.js';
import { formatMeters, stableId } from '../core/utilities.js';
import { haversineMeters, xyToLatLon } from '../location/location-privacy.js';
import { pointToSegmentProjection } from '../roads/geometry.js';
import { insertBaseNodeOnEdge } from './base-graph.js';

export class BasePlacementService {
  constructor(graph, originLocation) {
    this.graph = graph;
    this.originLocation = originLocation;
  }

  findNearestRoad(worldPoint, maxDistanceMeters = Infinity) {
    let best = null;
    for (const edge of this.graph.edges) {
      const a = this.graph.nodeById.get(edge.a);
      const b = this.graph.nodeById.get(edge.b);
      if (!a || !b) continue;
      const projection = pointToSegmentProjection(worldPoint, a, b);
      if (projection.distance > maxDistanceMeters) continue;
      if (!best || projection.distance < best.distanceToRoad) {
        const location = xyToLatLon(projection.point.x, projection.point.y, this.graph.center);
        const distanceFromOrigin = haversineMeters(this.originLocation, location);
        best = {
          edgeId: edge.id,
          point: projection.point,
          location,
          t: projection.t,
          distanceToRoad: projection.distance,
          distanceFromOrigin,
          valid: distanceFromOrigin <= ROAD_CONFIG.selectionRadiusMeters,
          label: `${formatMeters(distanceFromOrigin)}先の道路`
        };
      }
    }
    return best;
  }

  establishHomeBase(selection) {
    if (!selection?.valid) throw new Error('有効な道路を選択してください。');
    const insertion = insertBaseNodeOnEdge(this.graph, selection);
    return {
      graph: insertion.graph,
      homeBase: {
      id: stableId('home', selection.edgeId, selection.location.lat, selection.location.lon),
      status: 'ESTABLISHED',
      edgeId: selection.edgeId,
      nodeId: insertion.nodeId,
      x: selection.point.x,
      y: selection.point.y,
      location: {
        lat: selection.location.lat,
        lon: selection.location.lon
      },
      selectedDistanceMeters: selection.distanceFromOrigin,
      establishedAt: Date.now()
      }
    };
  }

  createHomeBase(selection) {
    return this.establishHomeBase(selection).homeBase;
  }
}
